type productsAPI struct{}

// Products is the catalog accessor.
var Products productsAPI

// Values returns every product slug, sorted alphabetically.
func (productsAPI) Values() []Product { return append([]Product(nil), allProducts...) }

// Metadata returns the metadata for p and whether p is known.
func (productsAPI) Metadata(p Product) (ProductMetadata, bool) {
	m, ok := productMetadata[p]
	return m, ok
}

// ByCarrier returns every product filed by the given carrier slug (case-insensitive).
func (productsAPI) ByCarrier(carrier string) []Product {
	target := strings.ToLower(strings.TrimSpace(carrier))
	out := make([]Product, 0)
	for _, p := range allProducts { if productMetadata[p].Carrier == target { out = append(out, p) } }
	return out
}
